import 'dart:async';

import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';
import 'package:study_app/routes/entity/my_webview_entity.dart';
import 'package:webview_flutter/webview_flutter.dart';

class DevWebViewFlutter extends StatefulWidget {
  static const String routeName = "/dev_webview_flutter";

  final MyWebViewEntity args;

  DevWebViewFlutter({this.args});

  @override
  _DevWebViewFlutterState createState() => _DevWebViewFlutterState();
}

class _DevWebViewFlutterState extends State<DevWebViewFlutter> {
  //webView控制器
  WebViewController webViewController;

  //标题
  String title;

  //地址
  String url;

  //获取网页标题
  Future<String> _getTitle() async {
    return await webViewController?.evaluateJavascript('document.title');
  }

  //js channel
  List<JavascriptChannel> _jsChanelApi(BuildContext context) {
    List<JavascriptChannel> chanelList = [];
    return chanelList;
  }

  @override
  void dispose() {
    // TODO: implement dispose
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return WillPopScope(
      onWillPop: () async{
        if (!(await webViewController.canGoBack()))
          Navigator.of(context).pop();
        else
          webViewController?.goBack();
        return Future.value(false);
      },
      child: Scaffold(
        appBar: AppBar(
          title: Text(title ?? widget.args?.title ?? "test webview_flutter"),
        ),
        body: Stack(
          children: <Widget>[
            WebView(
              initialUrl: widget.args?.url,
              // 加载的url
              javascriptMode: JavascriptMode.unrestricted,
              javascriptChannels: _jsChanelApi(context).toSet(),
              onWebViewCreated: (WebViewController web) async {
                webViewController = web;
              },
              onPageFinished: (String value) async {
                //网页改变完成调用
                if (null != webViewController) {
                  title = (await _getTitle() ?? "").replaceAll('"', '');
                  url = await webViewController.currentUrl();

                  //设置标题
                  setState(() {});
                  debugPrint(" ==> title：$title，url：$url");
                }
              },
            ),
          ],
        ),
      ),
    );
  }
}


